// Ensure output dir exists
if (!fs.existsSync(VAULT_PATH)) {
  fs.mkdirSync(VAULT_PATH, { recursive: true });
}

// Track existing files to avoid overwriting
const existing = new Set(
  fs.readdirSync(VAULT_PATH).map(f => f.replace('.md', ''))
);

let created = 0;
let skipped = 0;
const allCities = [];

for (const [stateName, cities] of Object.entries(citiesByState)) {
  const stateSlug = slugify(stateName);
  const uniqueCities = [...new Set(cities)]; // deduplicate within state

  for (const cityName of uniqueCities) {
    // Handle duplicate city names across states by appending state
    let filename = cityName;
    let displayName = cityName;

    if (existing.has(filename)) {
      // Check if existing file is for a different state
      const existingFile = path.join(VAULT_PATH, filename + '.md');
      if (fs.existsSync(existingFile)) {
        const content = fs.readFileSync(existingFile, 'utf8');
        if (!content.includes(`state: "${stateName}"`)) {
          // Different state - use "City, ST" format
          filename = `${cityName} (${states[stateName]})`;
        } else {
          skipped++;
          allCities.push({ name: cityName, state: stateName, slug: slugify(cityName) });
          continue; // Already exists for this state
        }
      }
    }

    if (existing.has(filename)) {
      skipped++;
      allCities.push({ name: cityName, state: stateName, slug: slugify(cityName) });
      continue;
    }

    existing.add(filename);

    const citySlug = slugify(cityName);

    const md = `---
type: city
name: "${cityName}"
slug: "${citySlug}"
state: "${stateName}"
state_slug: "${stateSlug}"
---

# ${cityName} Attorneys

Find experienced attorneys in ${cityName}, ${stateName}. Browse by practice area to find the right lawyer for your needs.

## Practice Areas
- [[Personal Injury]]
- [[Criminal Defense]]
- [[Divorce Law]]
- [[Business Law]]
- [[Real Estate Law]]
- [[Immigration Law]]
- [[Estate Planning]]
- [[Employment Law]]
- [[Bankruptcy]]
- [[Tax Law]]
`;

    const filePath = path.join(VAULT_PATH, filename + '.md');
    fs.writeFileSync(filePath, md);
    created++;
    allCities.push({ name: cityName, state: stateName, slug: citySlug });
  }
}

console.log(`Created: ${created} new city files`);
console.log(`Skipped: ${skipped} (already existed)`);
console.log(`Total city files: ${fs.readdirSync(VAULT_PATH).filter(f => f.endsWith('.md')).length}`);

// Save dataset JSON for Next.js to use
const datasetPath = path.join(__dirname, '..', 'vault', 'Datasets', 'cities.json');
fs.writeFileSync(datasetPath, JSON.stringify(allCities, null, 2));
console.log(`Saved cities dataset to ${datasetPath} (${allCities.length} entries)`);
